@namespace Lumeo

@{
    var focusedItemId = _focusedIndex >= 0 && _focusedIndex < _items.Count ? _items[_focusedIndex].Id : null;
    var focusedItemValue = _focusedIndex >= 0 && _focusedIndex < _items.Count ? _items[_focusedIndex].Value : null;
    var context = new SelectContext(Value, Open, Searchable, SearchText, Multiple, Values, IsLoading, Disabled, Clearable, Creatable, MaxDisplayTags,
        EventCallback.Factory.Create<string>(this, OnValueSelected),
        EventCallback.Factory.Create<bool>(this, SetOpen),
        EventCallback.Factory.Create<string>(this, OnSearchChanged),
        EventCallback.Factory.Create(this, OnClear),
        EventCallback.Factory.Create<string>(this, OnCreateItem),
        _wrapperId, _contentId, _focusedIndex, focusedItemId, focusedItemValue,
        EventCallback.Factory.Create<int>(this, SetFocusedIndex),
        RegisterItem, UnregisterItem, EffectiveInvalid, Required,
        Items, ItemValue, ItemText, ItemGroup, ItemDisabled, ItemTemplate, Virtualize, ItemSize);
}

@if (Label is not null && !InsideFormField)
{
    <label class="block text-sm font-medium mb-1.5">
        @Label
        @if (Required)
        {
            <span class="text-destructive ms-0.5">*</span>
        }
    </label>
}

<CascadingValue Value="context" IsFixed="false">
    <div id="@_wrapperId" class="relative" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@if (!InsideFormField)
{
    @if (EffectiveInvalid && !string.IsNullOrEmpty(ErrorText))
    {
        <p class="mt-1 text-xs text-destructive" role="alert" aria-live="polite">@ErrorText</p>
    }
    else if (!string.IsNullOrEmpty(HelperText))
    {
        <p class="mt-1 text-xs text-muted-foreground">@HelperText</p>
    }
}

@code {
    [CascadingParameter] private FormField.FormFieldContext? FormField { get; set; }

    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Value { get; set; }
    [Parameter] public EventCallback<string?> ValueChanged { get; set; }
    /// <summary>
    /// Popover open state. Bind via <c>@bind-Open</c> when the Select lives inside
    /// a parent that re-renders heavily (e.g. an <c>EditForm</c> with active
    /// validation) — otherwise a parameter cascade can close the popover mid-click.
    /// In the bound (controlled) mode the parent owns state and the popover survives
    /// re-renders. When unbound, the component still functions but is vulnerable to
    /// the cascade-close race; binding is the recommended pattern.
    /// </summary>
    [Parameter] public bool Open { get; set; }
    [Parameter] public EventCallback<bool> OpenChanged { get; set; }

    [Obsolete("Use Open instead. IsOpen will be removed in a future release.")]
    [Parameter] public bool IsOpen { get => Open; set => Open = value; }

    [Obsolete("Use OpenChanged instead. IsOpenChanged will be removed in a future release.")]
    [Parameter] public EventCallback<bool> IsOpenChanged { get => OpenChanged; set => OpenChanged = value; }

    [Parameter] public bool Searchable { get; set; }
    [Parameter] public bool Multiple { get; set; }
    [Parameter] public List<string>? Values { get; set; }
    [Parameter] public EventCallback<List<string>?> ValuesChanged { get; set; }
    [Parameter] public bool Clearable { get; set; }
    [Parameter] public bool Creatable { get; set; }
    [Parameter] public EventCallback<string> OnCreate { get; set; }
    [Parameter] public int MaxDisplayTags { get; set; } = 3;
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public bool Required { get; set; }
    [Parameter] public bool Invalid { get; set; }
    [Parameter] public string? ErrorText { get; set; }
    [Parameter] public string? HelperText { get; set; }
    [Parameter] public string? Label { get; set; }
    [Parameter] public string? Name { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    // --- Data-bound mode (non-generic, purely additive) ---
    /// <summary>Optional data source. When set, <see cref="SelectContent"/> renders options from this list instead of ChildContent.</summary>
    [Parameter] public IEnumerable<object>? Items { get; set; }
    /// <summary>Extracts the string value for each item. Defaults to <c>ToString()</c>.</summary>
    [Parameter] public Func<object, string> ItemValue { get; set; } = it => it?.ToString() ?? "";
    /// <summary>Extracts the display label for each item. Defaults to <see cref="ItemValue"/> when null.</summary>
    [Parameter] public Func<object, string>? ItemText { get; set; }
    /// <summary>Optional group key extractor. When set, options are grouped under sticky headers.</summary>
    [Parameter] public Func<object, string?>? ItemGroup { get; set; }
    /// <summary>Optional per-item disabled predicate.</summary>
    [Parameter] public Func<object, bool>? ItemDisabled { get; set; }
    /// <summary>Optional custom render fragment for an item's content. Receives the raw item object.</summary>
    [Parameter] public RenderFragment<object>? ItemTemplate { get; set; }
    /// <summary>When <c>true</c> and <see cref="Items"/> is set, uses Blazor's Virtualize component for the option list.</summary>
    [Parameter] public bool Virtualize { get; set; }
    /// <summary>Estimated pixel height of each option row used by the Virtualize component. Default 36.</summary>
    [Parameter] public float ItemSize { get; set; } = 36f;

    private bool EffectiveInvalid => Invalid || FormField?.HasError == true;
    private bool InsideFormField => FormField is not null;

    private readonly string _wrapperId = LumeoIds.New("select");
    private readonly string _contentId = LumeoIds.New("select-content");
    private string SearchText { get; set; } = "";
    private int _focusedIndex = -1;
    private readonly List<(string Id, string Value)> _items = new();

    private void RegisterItem(string id, string value)
    {
        if (!_items.Any(i => i.Id == id))
            _items.Add((id, value));
    }

    private void UnregisterItem(string id)
    {
        _items.RemoveAll(i => i.Id == id);
    }

    private async Task SetFocusedIndex(int index)
    {
        var count = _items.Count;
        if (count == 0) return;
        if (index < 0) index = 0;
        if (index >= count) index = count - 1;
        _focusedIndex = index;
        StateHasChanged();
        await Task.CompletedTask;
    }

    private async Task OnValueSelected(string value)
    {
        if (Multiple)
        {
            var current = Values ?? new List<string>();
            if (current.Contains(value))
            {
                current = current.Where(v => v != value).ToList();
            }
            else
            {
                current = new List<string>(current) { value };
            }
            Values = current.Count > 0 ? current : null;
            await ValuesChanged.InvokeAsync(Values);
        }
        else
        {
            Value = value;
            await ValueChanged.InvokeAsync(value);
            await SetOpen(false);
        }
    }

    private async Task SetOpen(bool value)
    {
        Open = value;
        if (!value)
        {
            SearchText = "";
            _focusedIndex = -1;
            _items.Clear();
        }
        await OpenChanged.InvokeAsync(value);
    }

    private Task OnSearchChanged(string text)
    {
        SearchText = text;
        _focusedIndex = -1;
        _items.Clear();
        return Task.CompletedTask;
    }

    private async Task OnClear()
    {
        if (Multiple)
        {
            Values = null;
            await ValuesChanged.InvokeAsync(null);
        }
        else
        {
            Value = null;
            await ValueChanged.InvokeAsync(null);
        }
    }

    private async Task OnCreateItem(string value)
    {
        await OnCreate.InvokeAsync(value);
        if (Multiple)
        {
            var current = Values ?? new List<string>();
            current = new List<string>(current) { value };
            Values = current;
            await ValuesChanged.InvokeAsync(Values);
        }
        else
        {
            Value = value;
            await ValueChanged.InvokeAsync(value);
            await SetOpen(false);
        }
        SearchText = "";
    }

    public record SelectContext(
        string? Value, bool IsOpen, bool Searchable, string SearchText,
        bool Multiple, List<string>? Values, bool IsLoading, bool Disabled, bool Clearable, bool Creatable, int MaxDisplayTags,
        EventCallback<string> OnSelect, EventCallback<bool> SetOpen, EventCallback<string> OnSearch,
        EventCallback OnClear, EventCallback<string> OnCreateItem,
        string WrapperId, string ContentId, int FocusedIndex, string? FocusedItemId, string? FocusedItemValue,
        EventCallback<int> SetFocusedIndex,
        Action<string, string> RegisterItem, Action<string> UnregisterItem,
        bool Invalid, bool Required,
        // Data-bound mode params (null when composition mode)
        IEnumerable<object>? Items,
        Func<object, string> ItemValue,
        Func<object, string>? ItemText,
        Func<object, string?>? ItemGroup,
        Func<object, bool>? ItemDisabled,
        RenderFragment<object>? ItemTemplate,
        bool Virtualize,
        float ItemSize);
}

@namespace Lumeo
@implements IAsyncDisposable
@using Microsoft.AspNetCore.Components.Web.Virtualization

@if (Context.IsOpen)
{
    <div id="@Context.ContentId" role="listbox" class="@CssClass"
         @onkeydown="HandleKeyDown" tabindex="-1" @attributes="AdditionalAttributes">
        @if (Context.Searchable)
        {
            <div class="px-1 pb-1">
                <input type="text" class="w-full rounded-sm border border-border/40 bg-background px-2 py-1 text-sm outline-none focus:ring-1 focus:ring-ring placeholder:text-muted-foreground"
                    placeholder="@L["Combobox.SearchPlaceholder"]"
                    value="@Context.SearchText"
                    @oninput="OnInput"
                    @onkeydown="HandleKeyDown"
                    @onclick:stopPropagation="true" />
            </div>
        }

        @if (Context.IsLoading)
        {
            <div class="flex items-center justify-center py-4">
                <Spinner Size="Lumeo.Size.Sm" class="text-muted-foreground" />
            </div>
        }
        else if (Context.Items is not null)
        {
            @* Data-bound mode: render items from the Items collection *@
            var filteredItems = FilteredItems;
            @if (Context.Virtualize)
            {
                <Virtualize Items="@filteredItems" Context="item" ItemSize="@Context.ItemSize">
                    @RenderBoundItem(item)
                </Virtualize>
            }
            else if (Context.ItemGroup is not null)
            {
                @* Grouped rendering *@
                @foreach (var group in filteredItems.GroupBy(i => Context.ItemGroup(i) ?? ""))
                {
                    <div role="group">
                        @if (!string.IsNullOrEmpty(group.Key))
                        {
                            <div class="px-2 py-1.5 text-sm font-semibold">@group.Key</div>
                        }
                        @foreach (var item in group)
                        {
                            @RenderBoundItem(item)
                        }
                    </div>
                }
            }
            else
            {
                @foreach (var item in filteredItems)
                {
                    @RenderBoundItem(item)
                }
            }

            @if (Context.Creatable && !string.IsNullOrWhiteSpace(Context.SearchText))
            {
                <button type="button" class="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 pl-2 pr-8 text-sm outline-none hover:bg-accent hover:text-accent-foreground"
                        @onclick="HandleCreate">
                    <Blazicon Svg="Lucide.Plus" class="h-3.5 w-3.5" />
                    <span>@string.Format(L["Combobox.Create"], Context.SearchText)</span>
                </button>
            }
        }
        else
        {
            @ChildContent

            @if (Context.Creatable && !string.IsNullOrWhiteSpace(Context.SearchText))
            {
                <button type="button" class="relative flex w-full cursor-default select-none items-center gap-2 rounded-sm py-1.5 pl-2 pr-8 text-sm outline-none hover:bg-accent hover:text-accent-foreground"
                        @onclick="HandleCreate">
                    <Blazicon Svg="Lucide.Plus" class="h-3.5 w-3.5" />
                    <span>@string.Format(L["Combobox.Create"], Context.SearchText)</span>
                </button>
            }
        }
    </div>
}

@inject IComponentInteropService Interop
@inject Lumeo.Services.Localization.ILumeoLocalizer L

@code {
    [CascadingParameter] public Select.SelectContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private bool _registered;

    /// <summary>Items filtered by the current search text (data-bound mode only).</summary>
    private List<object> FilteredItems
    {
        get
        {
            if (Context.Items is null) return [];
            if (!Context.Searchable || string.IsNullOrEmpty(Context.SearchText))
                return Context.Items.ToList();

            return Context.Items.Where(item =>
            {
                var text = Context.ItemText?.Invoke(item) ?? Context.ItemValue(item);
                return text.Contains(Context.SearchText, StringComparison.OrdinalIgnoreCase);
            }).ToList();
        }
    }

    private RenderFragment RenderBoundItem(object item) => builder =>
    {
        var value = Context.ItemValue(item);
        var isSelected = Context.Multiple
            ? Context.Values != null && Context.Values.Contains(value)
            : Context.Value == value;
        var isDisabled = Context.ItemDisabled?.Invoke(item) ?? false;
        var itemId = $"select-item-bound-{value.GetHashCode():X}";

        // Register/unregister happens inline for bound items — we track them through a simple button render
        // The keyboard nav uses the registered _items list on Select; bound items self-register by calling
        // Context.RegisterItem from here just like SelectItem does, but without a persistent component.
        // We render a plain button that matches SelectItem's markup so styling stays consistent.

        var isFocused = Context.FocusedItemId == itemId;

        builder.OpenElement(0, "button");
        builder.AddAttribute(1, "type", "button");
        builder.AddAttribute(2, "id", itemId);
        builder.AddAttribute(3, "role", "option");
        builder.AddAttribute(4, "aria-selected", isSelected.ToString().ToLower());
        builder.AddAttribute(5, "aria-disabled", isDisabled.ToString().ToLower());
        var cssClass = Cx.Join(
            "relative flex w-full select-none items-center gap-2 rounded-sm py-1.5 pl-2 pr-8 text-sm outline-none",
            isDisabled ? "opacity-50 cursor-not-allowed pointer-events-none" : "cursor-pointer hover:bg-accent hover:text-accent-foreground",
            Cx.When(isFocused && !isDisabled, "bg-accent text-accent-foreground"));
        builder.AddAttribute(6, "class", cssClass);
        if (!isDisabled)
        {
            builder.AddAttribute(7, "onclick", EventCallback.Factory.Create(this, () => Context.OnSelect.InvokeAsync(value)));
        }
        builder.OpenElement(8, "span");
        builder.AddAttribute(9, "class", "flex h-3.5 w-3.5 shrink-0 items-center justify-center");
        if (isSelected)
        {
            builder.OpenComponent<Blazicons.Blazicon>(10);
            builder.AddAttribute(11, "Svg", Blazicons.Lucide.Check);
            builder.AddAttribute(12, "class", "h-3.5 w-3.5");
            builder.CloseComponent();
        }
        builder.CloseElement(); // span

        if (Context.ItemTemplate is not null)
        {
            builder.AddContent(13, Context.ItemTemplate(item));
        }
        else
        {
            var label = Context.ItemText?.Invoke(item) ?? value;
            builder.AddContent(13, label);
        }
        builder.CloseElement(); // button
    };

    private string CssClass => $"fixed z-50 min-w-[8rem] overflow-hidden rounded-md border border-border/40 bg-popover p-1 text-popover-foreground shadow-lg animate-fade-in {Class}".Trim();

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (Context.IsOpen && !_registered)
        {
            await Interop.PositionFixed(Context.ContentId, Context.WrapperId, "start", true);
            await Interop.RegisterClickOutside(Context.ContentId, null, async () =>
            {
                await Context.SetOpen.InvokeAsync(false);
                await InvokeAsync(StateHasChanged);
            });
            _registered = true;
        }
        else if (!Context.IsOpen && _registered)
        {
            await Cleanup();
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
            case "ArrowDown":
                await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex + 1);
                break;
            case "ArrowUp":
                await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex > 0 ? Context.FocusedIndex - 1 : 0);
                break;
            case "Home":
                await Context.SetFocusedIndex.InvokeAsync(0);
                break;
            case "End":
                await Context.SetFocusedIndex.InvokeAsync(int.MaxValue);
                break;
            case "Enter":
                if (Context.FocusedItemValue is not null)
                    await Context.OnSelect.InvokeAsync(Context.FocusedItemValue);
                break;
        }
    }

    private async Task OnInput(ChangeEventArgs e)
    {
        await Context.OnSearch.InvokeAsync(e.Value?.ToString() ?? "");
    }

    private async Task HandleCreate()
    {
        await Context.OnCreateItem.InvokeAsync(Context.SearchText);
    }

    private async Task Cleanup()
    {
        try { await Interop.UnpositionFixed(Context.ContentId); } catch (JSDisconnectedException) { }
        try { await Interop.UnregisterClickOutside(Context.ContentId); } catch (JSDisconnectedException) { }
        _registered = false;
    }

    public async ValueTask DisposeAsync()
    {
        if (_registered) await Cleanup();
    }
}

@namespace Lumeo

<CascadingValue Value="_groupContext" IsFixed="false">
    <div role="group" aria-labelledby="@_groupContext.LabelId" class="@CssClass" @attributes="AdditionalAttributes">
        @ChildContent
    </div>
</CascadingValue>

@code {
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly SelectGroupContext _groupContext = new(LumeoIds.New("select-label"));

    private string CssClass => $"p-1 {Class}".Trim();

    public record SelectGroupContext(string LabelId);
}

@namespace Lumeo
@implements IDisposable

@if (Visible)
{
    <button type="button" id="@_itemId" role="option" aria-selected="@IsSelected.ToString().ToLower()"
            aria-disabled="@Disabled.ToString().ToLower()"
            class="@CssClass" @onclick="HandleSelect" @attributes="AdditionalAttributes">
        <span class="flex h-3.5 w-3.5 shrink-0 items-center justify-center">
            @if (IsSelected)
            {
                <Blazicon Svg="Lucide.Check" class="h-3.5 w-3.5" />
            }
        </span>
        @ChildContent
    </button>
}

@code {
    [CascadingParameter] public Select.SelectContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter, EditorRequired] public string Value { get; set; } = "";
    [Parameter] public bool Disabled { get; set; }
    [Parameter] public string? Class { get; set; }
    /// <summary>Optional text used to match against the search input when Searchable is enabled. Falls back to Value.</summary>
    [Parameter] public string? SearchValue { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _itemId = LumeoIds.New("select-item");
    private bool _registered;

    private bool IsSelected => Context.Multiple
        ? Context.Values != null && Context.Values.Contains(Value)
        : Context.Value == Value;

    private bool IsFocused => Context.FocusedItemId == _itemId;

    private bool Visible
    {
        get
        {
            if (!Context.Searchable || string.IsNullOrEmpty(Context.SearchText)) return true;
            var haystack = SearchValue ?? Value;
            return haystack.Contains(Context.SearchText, StringComparison.OrdinalIgnoreCase);
        }
    }

    private string CssClass => Cx.Join(
        "relative flex w-full select-none items-center gap-2 rounded-sm py-1.5 pl-2 pr-8 text-sm outline-none",
        Disabled ? "opacity-50 cursor-not-allowed pointer-events-none" : "cursor-pointer hover:bg-accent hover:text-accent-foreground",
        Cx.When(IsFocused && !Disabled, "bg-accent text-accent-foreground"),
        Class);

    protected override void OnParametersSet()
    {
        if (Visible && !_registered)
        {
            Context.RegisterItem(_itemId, Value);
            _registered = true;
        }
        else if (!Visible && _registered)
        {
            Context.UnregisterItem(_itemId);
            _registered = false;
        }
    }

    public void Dispose()
    {
        if (_registered) Context.UnregisterItem(_itemId);
    }

    private async Task HandleSelect()
    {
        if (Disabled) return;
        await Context.OnSelect.InvokeAsync(Value);
    }
}

@namespace Lumeo

<div id="@LabelId" class="@CssClass" @attributes="AdditionalAttributes">
    @ChildContent
</div>

@code {
    [CascadingParameter] public SelectGroup.SelectGroupContext? GroupContext { get; set; }
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private string LabelId => GroupContext?.LabelId ?? LumeoIds.New("select-label");

    private string CssClass => $"px-2 py-1.5 text-sm font-semibold {Class}".Trim();
}

@namespace Lumeo
@inject Lumeo.Services.Localization.ILumeoLocalizer L

<button type="button" id="@_triggerId"
        role="combobox"
        aria-haspopup="listbox"
        aria-expanded="@Context.IsOpen.ToString().ToLower()"
        aria-controls="@Context.ContentId"
        aria-activedescendant="@(Context.IsOpen ? Context.FocusedItemId : null)"
        class="@CssClass"
        disabled="@Context.Disabled"
        @onclick="Toggle"
        @onkeydown="HandleKeyDown"
        @attributes="AdditionalAttributes">
    @if (Context.Multiple && Context.Values != null && Context.Values.Count > 0)
    {
        <div class="flex flex-wrap gap-1 items-center flex-1 min-w-0">
            @{
                var displayed = Context.Values.Take(Context.MaxDisplayTags).ToList();
                var remaining = Context.Values.Count - Context.MaxDisplayTags;
            }
            @foreach (var val in displayed)
            {
                <span class="inline-flex items-center gap-1 rounded-md border border-border/40 bg-secondary px-1.5 py-0.5 text-xs font-medium text-secondary-foreground">
                    @val
                    <button type="button" class="cursor-pointer rounded-full hover:bg-foreground/20 focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1" aria-label="@($"Remove {val}")" @onclick="() => RemoveValue(val)" @onclick:stopPropagation="true">
                        <Blazicon Svg="Lucide.X" class="h-3 w-3" />
                    </button>
                </span>
            }
            @if (remaining > 0)
            {
                <span class="text-xs text-muted-foreground">+@remaining more</span>
            }
        </div>
    }
    else if (HasValue)
    {
        @ChildContent
    }
    else
    {
        <span class="text-muted-foreground">@(Placeholder ?? L["Select.Placeholder"])</span>
    }

    <div class="flex items-center gap-1 ms-auto shrink-0">
        @if (Context.Clearable && HasValue)
        {
            <button type="button" class="cursor-pointer hover:text-foreground focus-visible:outline-none focus-visible:ring-[1.5px] focus-visible:ring-ring focus-visible:ring-offset-1 rounded" aria-label="@L["Select.ClearSelection"]" @onclick="HandleClear" @onclick:stopPropagation="true">
                <Blazicon Svg="Lucide.X" class="h-3.5 w-3.5 opacity-50 hover:opacity-100" />
            </button>
        }
        <Blazicon Svg="Lucide.ChevronDown" class="@($"h-4 w-4 shrink-0 opacity-50 transition-transform duration-200 {(Context.IsOpen ? "rotate-180" : "")}")" />
    </div>
</button>

@code {
    [CascadingParameter] public Select.SelectContext Context { get; set; } = default!;
    [Parameter] public RenderFragment? ChildContent { get; set; }
    [Parameter] public string? Placeholder { get; set; }
    [Parameter] public string? Class { get; set; }
    [Parameter(CaptureUnmatchedValues = true)] public Dictionary<string, object>? AdditionalAttributes { get; set; }

    private readonly string _triggerId = LumeoIds.New("select-trigger");

    private bool HasValue => Context.Multiple
        ? Context.Values != null && Context.Values.Count > 0
        : !string.IsNullOrEmpty(Context.Value);

    private string CssClass => $"flex h-9 w-full cursor-pointer items-center justify-between whitespace-nowrap rounded-md border {(Context.Invalid ? "border-destructive" : "border-input")} bg-transparent px-3 py-2 text-sm placeholder:text-muted-foreground focus-visible:outline-none focus-visible:ring-2 {(Context.Invalid ? "focus-visible:ring-destructive/20" : "focus-visible:ring-ring")} focus-visible:ring-offset-2 disabled:cursor-not-allowed disabled:opacity-50 {Class}".Trim();

    private async Task Toggle() => await Context.SetOpen.InvokeAsync(!Context.IsOpen);

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        switch (e.Key)
        {
            case "ArrowDown":
                if (!Context.IsOpen)
                    await Context.SetOpen.InvokeAsync(true);
                else
                    await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex + 1);
                break;
            case "ArrowUp":
                if (!Context.IsOpen)
                    await Context.SetOpen.InvokeAsync(true);
                else
                    await Context.SetFocusedIndex.InvokeAsync(Context.FocusedIndex > 0 ? Context.FocusedIndex - 1 : 0);
                break;
            case "Enter":
            case " ":
                if (!Context.IsOpen)
                    await Context.SetOpen.InvokeAsync(true);
                else if (Context.FocusedItemValue is not null)
                    await Context.OnSelect.InvokeAsync(Context.FocusedItemValue);
                break;
            case "Escape":
                await Context.SetOpen.InvokeAsync(false);
                break;
            case "Home":
                if (Context.IsOpen)
                    await Context.SetFocusedIndex.InvokeAsync(0);
                break;
            case "End":
                if (Context.IsOpen)
                    await Context.SetFocusedIndex.InvokeAsync(int.MaxValue);
                break;
        }
    }

    private async Task RemoveValue(string value)
    {
        await Context.OnSelect.InvokeAsync(value);
    }

    private async Task HandleClear()
    {
        await Context.OnClear.InvokeAsync();
    }
}
